import type { Metadata } from "next";
import PortfolioDashboard from "./PortfolioDashboard";

export const metadata: Metadata = {
  title: "資産推移 | ぐんじょう銀行",
  description:
    "総資産・資産推移・資産配分・保有銘柄をまとめて確認できる資産管理ダッシュボード",
};

export default function PortfolioPage() {
  return <PortfolioDashboard />;
}

// ---------------------------------------------------------------------------
// Synthetic-but-realistic portfolio data for the 資産推移ダッシュボード.
// Deterministic (seeded) so SSR and client render identically — no hydration
// mismatch, no Math.random() at module scope.
// ---------------------------------------------------------------------------

export type RangeKey = "1m" | "3m" | "6m" | "1y" | "all";

export interface RangeOption {
  key: RangeKey;
  label: string;
  /** Number of months of history to show. "all" = full series. */
  months: number | "all";
}

export const RANGE_OPTIONS: RangeOption[] = [
  { key: "1m", label: "1ヶ月", months: 1 },
  { key: "3m", label: "3ヶ月", months: 3 },
  { key: "6m", label: "6ヶ月", months: 6 },
  { key: "1y", label: "1年", months: 12 },
  { key: "all", label: "全期間", months: "all" },
];

export interface SeriesPoint {
  /** ISO-ish date label, already JP-formatted for axis. */
  date: string;
  /** Total net worth in yen on that day. */
  value: number;
}

// ---- seeded series generation (mulberry32) --------------------------------
function mulberry32(seed: number) {
  return function () {
    seed |= 0;
    seed = (seed + 0x6d2b79f5) | 0;
    let t = Math.imul(seed ^ (seed >>> 15), 1 | seed);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

/**
 * 24 months of daily-ish net-worth points (one per ~3 days = 240 points),
 * trending up with realistic volatility and a couple of drawdowns. Ends today.
 */
const FULL_SERIES: SeriesPoint[] = (() => {
  const rand = mulberry32(20260622);
  const points: SeriesPoint[] = [];
  const today = new Date(2026, 5, 22); // 2026-06-22, fixed for determinism
  const STEP_DAYS = 3;
  const COUNT = 240; // ~720 days back
  let value = 9_800_000; // ~2 years ago
  for (let i = COUNT - 1; i >= 0; i--) {
    const d = new Date(today);
    d.setDate(today.getDate() - i * STEP_DAYS);
    // upward drift + noise + a mid-period dip
    const drift = 9_500;
    const noise = (rand() - 0.45) * 95_000;
    const dip = i > 70 && i < 95 ? -38_000 : 0; // a correction ~8 months ago
    const dip2 = i > 18 && i < 30 ? -52_000 : 0; // a recent wobble
    value = Math.max(7_500_000, value + drift + noise + dip + dip2);
    points.push({
      date: `${d.getFullYear()}/${String(d.getMonth() + 1).padStart(2, "0")}/${String(
        d.getDate()
      ).padStart(2, "0")}`,
      value: Math.round(value),
    });
  }
  return points;
})();

export const TOTAL_NET_WORTH = FULL_SERIES[FULL_SERIES.length - 1].value;
const PREV_DAY_VALUE = FULL_SERIES[FULL_SERIES.length - 2].value;
export const TODAY_CHANGE = TOTAL_NET_WORTH - PREV_DAY_VALUE;
export const TODAY_CHANGE_PCT = (TODAY_CHANGE / PREV_DAY_VALUE) * 100;

/**
 * Return a down-sampled series for a range (≈12 points so axis labels stay
 * readable — FINDING F6: LineChart renders one axis label per point and has no
 * tick-thinning prop, so we thin the data ourselves).
 */
export function seriesForRange(key: RangeKey): SeriesPoint[] {
  const opt = RANGE_OPTIONS.find((o) => o.key === key) ?? RANGE_OPTIONS[3];
  let slice: SeriesPoint[];
  if (opt.months === "all") {
    slice = FULL_SERIES;
  } else {
    // ~10 points per month of source data (STEP_DAYS=3 => ~10/mo)
    const take = Math.round(opt.months * 10);
    slice = FULL_SERIES.slice(Math.max(0, FULL_SERIES.length - take));
  }
  const TARGET = 12;
  if (slice.length <= TARGET) return slice;
  const step = (slice.length - 1) / (TARGET - 1);
  const out: SeriesPoint[] = [];
  for (let i = 0; i < TARGET; i++) {
    out.push(slice[Math.round(i * step)]);
  }
  // always end on the latest point
  out[out.length - 1] = slice[slice.length - 1];
  return out;
}

/** Net worth at the start of the range, for "期間内増減" stats. */
export function rangeChange(key: RangeKey): { abs: number; pct: number } {
  const s = seriesForRange(key);
  if (s.length < 2) return { abs: 0, pct: 0 };
  const first = s[0].value;
  const last = s[s.length - 1].value;
  return { abs: last - first, pct: ((last - first) / first) * 100 };
}

// ---- allocation by asset class (sums to TOTAL_NET_WORTH) -------------------
export interface Allocation {
  label: string;
  value: number;
  color: "primary" | "success" | "warning" | "info" | "accent" | "destructive";
}

export const ALLOCATION: Allocation[] = [
  { label: "預金", value: 4_100_000, color: "info" },
  { label: "株式", value: 3_250_000, color: "primary" },
  { label: "投資信託", value: 2_480_000, color: "success" },
  { label: "債券", value: 1_150_000, color: "accent" },
  { label: "外貨預金", value: 720_000, color: "warning" },
  { label: "暗号資産", value: 360_000, color: "destructive" },
];

// ---- holdings / accounts with per-row trend + P/L --------------------------
export interface Holding {
  id: string;
  name: string;
  kind: string;
  /** 評価額 (current valuation, yen). */
  value: number;
  /** 評価損益 (signed yen). Can be negative. */
  pl: number;
  /** 評価損益率 (signed %). */
  plPct: number;
  /** recent trend for the row sparkline (raw values). */
  trend: number[];
}

export const HOLDINGS: Holding[] = [
  {
    id: "h1",
    name: "ぐんじょう普通預金",
    kind: "預金",
    value: 4_100_000,
    pl: 0,
    plPct: 0,
    trend: [4.08, 4.09, 4.1, 4.1, 4.11, 4.1, 4.1].map((v) => v * 1e6),
  },
  {
    id: "h2",
    name: "全世界株式インデックス",
    kind: "投資信託",
    value: 2_480_000,
    pl: 412_000,
    plPct: 19.93,
    trend: [2.05, 2.12, 2.18, 2.31, 2.4, 2.46, 2.48].map((v) => v * 1e6),
  },
  {
    id: "h3",
    name: "トヨタ自動車 (7203)",
    kind: "国内株式",
    value: 1_180_000,
    pl: 138_000,
    plPct: 13.25,
    trend: [1.02, 1.05, 1.04, 1.09, 1.12, 1.16, 1.18].map((v) => v * 1e6),
  },
  {
    id: "h4",
    name: "Apple Inc. (AAPL)",
    kind: "外国株式",
    value: 2_070_000,
    pl: -94_000,
    plPct: -4.34,
    trend: [2.18, 2.21, 2.16, 2.12, 2.09, 2.05, 2.07].map((v) => v * 1e6),
  },
  {
    id: "h5",
    name: "国内債券ファンド",
    kind: "債券",
    value: 1_150_000,
    pl: 12_000,
    plPct: 1.05,
    trend: [1.14, 1.14, 1.145, 1.15, 1.148, 1.149, 1.15].map((v) => v * 1e6),
  },
  {
    id: "h6",
    name: "米ドル外貨預金",
    kind: "外貨預金",
    value: 720_000,
    pl: 36_000,
    plPct: 5.26,
    trend: [0.69, 0.7, 0.7, 0.71, 0.715, 0.72, 0.72].map((v) => v * 1e6),
  },
  {
    id: "h7",
    name: "ビットコイン",
    kind: "暗号資産",
    value: 360_000,
    pl: -58_000,
    plPct: -13.88,
    trend: [0.43, 0.41, 0.39, 0.42, 0.38, 0.37, 0.36].map((v) => v * 1e6),
  },
];

// ---- KPI roll-ups ----------------------------------------------------------
export const TOTAL_PL = HOLDINGS.reduce((s, h) => s + h.pl, 0);
export const TOTAL_COST = HOLDINGS.reduce((s, h) => s + (h.value - h.pl), 0);
export const TOTAL_PL_PCT = TOTAL_COST > 0 ? (TOTAL_PL / TOTAL_COST) * 100 : 0;
/** 当月の配当・利息 (received income). */
export const INCOME_THIS_MONTH = 18_420;
export const INCOME_PREV_MONTH = 16_900;

// ---------------------------------------------------------------------------
// HAND-ROLLED yen / percent formatters.
//
// FINDING (F1): @gunjo/ui ships NO currency/locale/compact number formatter.
// Its `defaultChartValueFormatter` is `Intl.NumberFormat("en-US")` — no ¥, no
// sign control, no compact mode, locale hard-coded. A fintech screen needs yen
// formatting in the header, KPI cards, table cells, chart tooltips, donut
// center and axis, so we hand-roll it here and pass it into every chart's
// `formatValue`. (The transfer screen hit the same gap in app/transfer/data.ts.)
// ---------------------------------------------------------------------------

/** `1234567` -> `¥1,234,567` (no decimals, ja-JP grouping). */
export function yen(amount: number): string {
  return `¥${Math.round(amount).toLocaleString("ja-JP")}`;
}

/** Signed yen for gain/loss, e.g. `+¥34,500` / `−¥120,000`. Uses a real minus. */
export function signedYen(amount: number): string {
  const sign = amount > 0 ? "+" : amount < 0 ? "−" : "±";
  return `${sign}¥${Math.abs(Math.round(amount)).toLocaleString("ja-JP")}`;
}

/** Signed percent, e.g. `+2.41%` / `−0.80%`. */
export function signedPct(pct: number): string {
  const sign = pct > 0 ? "+" : pct < 0 ? "−" : "±";
  return `${sign}${Math.abs(pct).toFixed(2)}%`;
}

/** Compact yen for crowded axis/tooltip labels: ¥12,300,000 -> `1,230万`, ¥120,000,000 -> `1.2億`. */
export function compactYen(amount: number): string {
  const abs = Math.abs(amount);
  const sign = amount < 0 ? "−" : "";
  if (abs >= 1e8) return `${sign}¥${(abs / 1e8).toFixed(abs % 1e8 === 0 ? 0 : 1)}億`;
  if (abs >= 1e4) return `${sign}¥${Math.round(abs / 1e4).toLocaleString("ja-JP")}万`;
  return `${sign}¥${abs.toLocaleString("ja-JP")}`;
}

/** Plain grouped number (no currency), for share counts etc. */
export function num(value: number): string {
  return value.toLocaleString("ja-JP");
}

/** Tone + trend for a signed value — drives Statistic/AnalyticsCard semantics. */
export function gainTone(value: number): {
  trend: "up" | "down" | "flat";
  tone: "positive" | "negative" | "neutral";
} {
  if (value > 0) return { trend: "up", tone: "positive" };
  if (value < 0) return { trend: "down", tone: "negative" };
  return { trend: "flat", tone: "neutral" };
}

/** Chart tone name (maps to a token, NOT raw hex) for a signed value. */
export function gainChartColor(value: number): "success" | "destructive" | "muted" {
  if (value > 0) return "success";
  if (value < 0) return "destructive";
  return "muted";
}

"use client";

import * as React from "react";
import {
  AnalyticsCard,
  Badge,
  Button,
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  ChartLegend,
  Container,
  DataTable,
  DonutChart,
  EmptyState,
  LineChart,
  Separator,
  Skeleton,
  SparklineChart,
  Statistic,
  ToggleGroup,
  ToggleGroupItem,
  type ChartDataPoint,
  type ColumnDef,
} from "@gunjo/ui";
import {
  IconArrowDownRight,
  IconArrowUpRight,
  IconChartPie,
  IconCoin,
  IconMinus,
  IconWallet,
} from "@tabler/icons-react";

import {
  ALLOCATION,
  HOLDINGS,
  INCOME_PREV_MONTH,
  INCOME_THIS_MONTH,
  RANGE_OPTIONS,
  TODAY_CHANGE,
  TODAY_CHANGE_PCT,
  TOTAL_NET_WORTH,
  TOTAL_PL,
  TOTAL_PL_PCT,
  rangeChange,
  seriesForRange,
  type Holding,
  type RangeKey,
} from "./data";
import {
  compactYen,
  gainChartColor,
  gainTone,
  signedPct,
  signedYen,
  yen,
} from "./format";

// ===========================================================================
// 総資産ヘッダー — big yen total + 前日比 with sign/arrow/color (not color alone)
// ===========================================================================
function NetWorthHeader() {
  const { tone } = gainTone(TODAY_CHANGE);
  const isUp = TODAY_CHANGE > 0;
  const isDown = TODAY_CHANGE < 0;
  const ChangeIcon = isUp
    ? IconArrowUpRight
    : isDown
      ? IconArrowDownRight
      : IconMinus;
  const toneClass =
    tone === "positive"
      ? "text-success"
      : tone === "negative"
        ? "text-destructive"
        : "text-muted-foreground";
  const directionWord = isUp ? "増加" : isDown ? "減少" : "変動なし";

  return (
    <header className="flex flex-col gap-2">
      <p className="text-sm font-medium text-muted-foreground">総資産</p>
      <div className="flex flex-wrap items-end gap-x-4 gap-y-1">
        <h1 className="text-4xl font-bold tracking-tight tabular-nums sm:text-5xl">
          {yen(TOTAL_NET_WORTH)}
        </h1>
        <div
          className={`mb-1.5 inline-flex items-center gap-1.5 text-base font-semibold tabular-nums ${toneClass}`}
        >
          <ChangeIcon className="h-5 w-5" aria-hidden="true" />
          <span>
            {signedYen(TODAY_CHANGE)}（{signedPct(TODAY_CHANGE_PCT)}）
          </span>
          {/* SR-only words so gain/loss is never conveyed by color alone */}
          <span className="sr-only">前日比 {directionWord}</span>
          <Badge
            as="span"
            variant={
              tone === "positive"
                ? "success"
                : tone === "negative"
                  ? "destructive"
                  : "secondary"
            }
            className="ml-1"
          >
            前日比
          </Badge>
        </div>
      </div>
      <p className="text-sm text-muted-foreground">2026年6月22日 時点・8口座を集計</p>
    </header>
  );
}

// ===========================================================================
// KPI row — Statistic + AnalyticsCard (trend/tone => arrow + token color)
// ===========================================================================
function KpiRow() {
  const today = gainTone(TODAY_CHANGE);
  const pl = gainTone(TOTAL_PL);
  const incomeDelta = INCOME_THIS_MONTH - INCOME_PREV_MONTH;
  const income = gainTone(incomeDelta);

  return (
    <section aria-labelledby="kpi-heading">
      {/* sr-only h2 so heading order stays h1 -> h2 -> (AnalyticsCard's h3) ->
          h2..., never an h1 -> h3 skip. FINDING F10: AnalyticsCard's title is a
          hard-coded <h3> with no level prop. */}
      <h2 id="kpi-heading" className="sr-only">
        主要指標
      </h2>
      <div className="grid grid-cols-2 gap-3 lg:grid-cols-4">
      <Statistic
        label="総資産"
        value={yen(TOTAL_NET_WORTH)}
        className="tabular-nums"
        hint="預金・投資の合計"
      />
      <Statistic
        label="評価損益（累計）"
        value={signedYen(TOTAL_PL)}
        change={signedPct(TOTAL_PL_PCT)}
        trend={pl.trend}
        tone={pl.tone}
        className="tabular-nums"
      />
      <Statistic
        label="本日の損益"
        value={signedYen(TODAY_CHANGE)}
        change={signedPct(TODAY_CHANGE_PCT)}
        trend={today.trend}
        tone={today.tone}
        className="tabular-nums"
      />
      <AnalyticsCard
        title="今月の配当・利息"
        value={<span className="tabular-nums">{yen(INCOME_THIS_MONTH)}</span>}
        delta={signedYen(incomeDelta)}
        trend={income.trend}
        deltaDescription={`先月（${yen(INCOME_PREV_MONTH)}）との比較`}
        variant={income.tone === "positive" ? "positive" : "default"}
      />
      </div>
    </section>
  );
}

// ===========================================================================
// 資産推移チャート — LineChart(area) + ToggleGroup time-range + SR table fallback
// ===========================================================================
function NetWorthChart() {
  const [range, setRange] = React.useState<RangeKey>("1y");
  const series = React.useMemo(() => seriesForRange(range), [range]);
  const rc = React.useMemo(() => rangeChange(range), [range]);
  const rcTone = gainTone(rc.abs);
  const activeLabel =
    RANGE_OPTIONS.find((o) => o.key === range)?.label ?? "1年";

  // LineChart renders one axis label per point (FINDING F6: no tick-thinning
  // prop). 12 MM/DD labels overflow at 375px, so only label every other point —
  // the line keeps full resolution; blank labels just free up axis width.
  const chartData: ChartDataPoint[] = series.map((p, i) => ({
    label: i % 2 === 0 || i === series.length - 1 ? p.date.slice(5) : "",
    value: p.value,
  }));

  // FINDING F4: charts carry no auto gain/loss tone — compute & pass a token name.
  const lineTone = gainChartColor(rc.abs);
  const first = series[0]?.value ?? 0;
  const last = series[series.length - 1]?.value ?? 0;

  return (
    <Card>
      <CardHeader className="gap-3">
        <div className="flex flex-wrap items-start justify-between gap-3">
          <div className="space-y-1">
            <CardTitle as="h2" className="text-base">
              資産推移
            </CardTitle>
            <CardDescription>
              期間内増減{" "}
              <span
                className={
                  rcTone.tone === "positive"
                    ? "font-medium text-success"
                    : rcTone.tone === "negative"
                      ? "font-medium text-destructive"
                      : "font-medium text-muted-foreground"
                }
              >
                {signedYen(rc.abs)}（{signedPct(rc.pct)}）
              </span>
            </CardDescription>
          </div>

          {/* Time-range selector — ToggleGroup (FINDING F2: no DS period control).
              type=single + disallowEmpty => keyboard-operable, always one active. */}
          <ToggleGroup
            type="single"
            value={range}
            disallowEmpty
            size="sm"
            aria-label="表示期間"
            onValueChange={(v) => v && setRange(v as RangeKey)}
            className="flex-wrap justify-end"
          >
            {RANGE_OPTIONS.map((o) => (
              <ToggleGroupItem key={o.key} value={o.key} aria-label={`期間: ${o.label}`}>
                {o.label}
              </ToggleGroupItem>
            ))}
          </ToggleGroup>
        </div>
        {/* announce active range to AT */}
        <p className="sr-only" role="status" aria-live="polite">
          表示期間: {activeLabel}
        </p>
      </CardHeader>
      <CardContent className="space-y-3">
        {/* Accessible textual summary + visually-hidden data table fallback
            (FINDING F7: charts give per-point aria-labels but no whole-series
            summary / table alternative). */}
        <div
          role="img"
          aria-label={`資産推移 ${activeLabel}: ${yen(first)} から ${yen(
            last
          )} へ ${signedYen(rc.abs)}（${signedPct(rc.pct)}）`}
        >
          <LineChart
            variant="area"
            className="h-64 sm:h-72" // FINDING F5: height is fixed h-[260px], override via className
            series={[
              {
                label: "総資産",
                data: chartData,
                color: lineTone,
              },
            ]}
            showDots={false}
            showGrid
            formatValue={(v) => compactYen(v)}
          />
        </div>

        <table className="sr-only">
          <caption>資産推移（{activeLabel}）</caption>
          <thead>
            <tr>
              <th scope="col">日付</th>
              <th scope="col">総資産</th>
            </tr>
          </thead>
          <tbody>
            {series.map((p) => (
              <tr key={p.date}>
                <th scope="row">{p.date}</th>
                <td>{yen(p.value)}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </CardContent>
    </Card>
  );
}

// ===========================================================================
// 資産配分 — DonutChart + ChartLegend (percent share)
// ===========================================================================
function AllocationCard() {
  const total = ALLOCATION.reduce((s, a) => s + a.value, 0);
  const segments: ChartDataPoint[] = ALLOCATION.map((a) => ({
    label: a.label,
    value: a.value,
    color: a.color,
  }));
  // FINDING F1 + ChartLegend(F9): the vertical ChartLegend renders its `value`
  // as a single flex-shrink-0 / nowrap node and lays the row out with
  // justify-between — a long value (¥4,100,000・33.5%) overflows the card rather
  // than wrapping. Keep the legend value short (compact yen + %) and give the
  // legend the FULL card width below the donut so it never has to overflow.
  const legendItems = ALLOCATION.map((a) => ({
    label: a.label,
    value: `${compactYen(a.value)}・${((a.value / total) * 100).toFixed(1)}%`,
    color: a.color,
  }));

  return (
    <Card>
      <CardHeader>
        <CardTitle as="h2" className="text-base">
          資産配分
        </CardTitle>
        <CardDescription>資産クラス別の構成比</CardDescription>
      </CardHeader>
      <CardContent className="flex flex-col items-center gap-5">
        <DonutChart
          segments={segments}
          centerValue={<span className="text-xl">{compactYen(total)}</span>}
          centerLabel="総資産"
          formatValue={(v) => yen(v)}
          totalLabel="総資産"
          className="shrink-0"
        />
        <ChartLegend items={legendItems} variant="vertical" className="w-full" />
      </CardContent>
    </Card>
  );
}

// ===========================================================================
// 保有銘柄一覧 — DataTable with signed/colored P/L + per-row sparkline
// ===========================================================================
function PlCell({ pl, pct }: { pl: number; pct: number }) {
  const { tone } = gainTone(pl);
  const Icon =
    pl > 0 ? IconArrowUpRight : pl < 0 ? IconArrowDownRight : IconMinus;
  const cls =
    tone === "positive"
      ? "text-success"
      : tone === "negative"
        ? "text-destructive"
        : "text-muted-foreground";
  return (
    <div className={`flex flex-col items-end tabular-nums ${cls}`}>
      <span className="inline-flex items-center gap-1 font-medium">
        <Icon className="h-3.5 w-3.5" aria-hidden="true" />
        {signedYen(pl)}
      </span>
      <span className="text-xs">{signedPct(pct)}</span>
    </div>
  );
}

const holdingColumns: ColumnDef<Holding>[] = [
  {
    accessorKey: "name",
    header: "銘柄・口座",
    cell: ({ row }) => {
      const h = row.original;
      return (
        <div className="flex min-w-0 flex-col">
          <span className="font-medium text-foreground">{h.name}</span>
          <span className="text-xs text-muted-foreground">{h.kind}</span>
        </div>
      );
    },
  },
  {
    id: "trend",
    header: "推移",
    enableSorting: false,
    cell: ({ row }) => {
